columns.valueFormatting:
{{ (() => {
  const m = currentSourceRow?.meta;
  if (!m || typeof m !== 'object') return '';
  const pick = (k) => (m?.[k] == null ? null : m[k]);

  // Common roster meta fields
  const rosterNow = pick('rosterNow');
  const minPlayers = pick('minPlayers');
  const targetPlayers = pick('targetPlayers');
  const missingMin = pick('missingMin');
  const missingTarget = pick('missingTarget');

  const bits = [];
  if (rosterNow != null && minPlayers != null) bits.push(`Roster: ${rosterNow}/${minPlayers}`);
  if (targetPlayers != null) bits.push(`Target: ${targetPlayers}`);
  if (missingMin != null) bits.push(`missingMin: ${missingMin}`);
  if (missingTarget != null) bits.push(`missingTarget: ${missingTarget}`);

  // Fallback: show keys
  if (!bits.length) {
    const keys = Object.keys(m).slice(0, 6);
    return keys.length ? `meta keys: ${keys.join(', ')}${Object.keys(m).length > keys.length ? '…' : ''}` : '';
  }

  return bits.join(' · ');
})() }}

